  }

  // ── Helpers privados ──────────────────────────────────────────────────────

  Future<String> _getApkSavePath() async {
    // getExternalStorageDirectory() puede ser null en algunos dispositivos/emuladores;
    // usamos getTemporaryDirectory() como fallback seguro.
    Directory? dir;
    try {
      dir = await getExternalStorageDirectory();
    } catch (_) {
